std::string extract_array(const std::string &doc, const std::string &key) {
    std::string needle = "\"" + key + "\"";
    size_t k = doc.find(needle);
    if (k == std::string::npos) {
        return "";
    }
    size_t p = doc.find('[', k);
    if (p == std::string::npos) {
        return "";
    }
    int depth = 0;
    size_t start = p;
    for (size_t i = p; i < doc.size(); ++i) {
        if (doc[i] == '[') {
